rca of the issue.mitigation:
Endre csvEscape i lib/platform/am-admin-backup.ts:119-126 til: ```ts
export function csvEscape(value: string | null | undefined): string {
  if (value === null || value === undefined) return "";
  let s = String(value);
  // OWASP CSV formula-injection mitigering: prefiks =/+/-/@/TAB/CR med apostrof.
  if (/^[=+\-@\t\r]/.test(s)) s = "'" + s;
  if (s.includes('"') || s.includes(",") || s.includes("\n") || s.includes("\r")) {
    return `"${s.replace(/"/g, '""')}"`;
  }
  return s;
}
